import React, { useEffect, useState } from "react";

const CategoryManage = () => {
  const [categories, setCategories] = useState([]);
  const [categoryName, setCategoryName] = useState("");
  const [editing, setEditing] = useState(false);
  const [editCategoryId, setEditCategoryId] = useState(null);

  // ✅ Fetch categories on page load
  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/category");
      const data = await res.json();
      setCategories(data);
    } catch (error) {
      console.error("❌ Failed to fetch categories", error);
    }
  };

  // ✅ Handle Add / Update
  const handleSubmit = async (e) => {
    e.preventDefault();

    const token = localStorage.getItem("token");
    if (!token) {
      alert("Admin token not found. Please log in.");
      return;
    }

    const url = editing
      ? `http://localhost:5000/api/category/${editCategoryId}`
      : "http://localhost:5000/api/category";

    const method = editing ? "PUT" : "POST";

    try {
      const res = await fetch(url, {
        method,
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ name: categoryName }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.message || "Error");

      alert(`✅ Category ${editing ? "updated" : "added"} successfully!`);
      setCategoryName("");
      setEditing(false);
      setEditCategoryId(null);
      fetchCategories();
    } catch (err) {
      console.error(err);
      alert("❌ Failed to add/update category");
    }
  };

  // ✅ Edit button
  const handleEdit = (category) => {
    setEditing(true);
    setCategoryName(category.name);
    setEditCategoryId(category.id);
  };

  // ✅ Delete category
  const handleDelete = async (id) => {
    const token = localStorage.getItem("token");
    if (!token) {
      alert("Admin token not found. Please log in.");
      return;
    }

    if (!window.confirm("Are you sure you want to delete this category?")) return;

    try {
      const res = await fetch(`http://localhost:5000/api/category/${id}`, {
        method: "DELETE",
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.message || "Error");

      alert("🗑️ Category deleted successfully!");
      fetchCategories();
    } catch (err) {
      console.error(err);
      alert("❌ Failed to delete category");
    }
  };

  return (
    <div className="p-6 max-w-3xl mx-auto">
      <h2 className="text-2xl font-bold mb-4">{editing ? "Update" : "Add"} Category</h2>

      <form onSubmit={handleSubmit} className="flex gap-4 mb-6">
        <input
          type="text"
          value={categoryName}
          onChange={(e) => setCategoryName(e.target.value)}
          placeholder="Category Name"
          className="border px-4 py-2 w-full"
          required
        />
        <button
          type="submit"
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          {editing ? "Update" : "Add"}
        </button>
      </form>

      <h3 className="text-xl font-semibold mb-3">📂 Categories</h3>
      <table className="w-full border">
        <thead>
          <tr className="bg-gray-200">
            <th className="border px-4 py-2">ID</th>
            <th className="border px-4 py-2">Name</th>
            <th className="border px-4 py-2">Actions</th>
          </tr>
        </thead>
        <tbody>
          {categories.map((cat) => (
            <tr key={cat.id}>
              <td className="border px-4 py-2">{cat.id}</td>
              <td className="border px-4 py-2">{cat.name}</td>
              <td className="border px-4 py-2">
                <button
                  onClick={() => handleEdit(cat)}
                  className="bg-yellow-500 text-white px-3 py-1 rounded mr-2 hover:bg-yellow-600"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(cat.id)}
                  className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-700"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
          {categories.length === 0 && (
            <tr>
              <td colSpan="3" className="text-center py-4">No categories found.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default CategoryManage;
